        int[] diff = new int[n + 1];

        for (int[] b : bookings) {
            int first = b[0], last = b[1], seats = b[2];
            diff[first - 1] += seats;
            diff[last] -= seats;
        }

        int[] answer = new int[n];
        answer[0] = diff[0];
