class Solution {
    public boolean isZeroArray(int[] nums, int[][] queries) {
        int n = nums.length;
        int[] coverage = new int[n];

        for (int[] q : queries) {
            for (int i = q[0]; i <= q[1]; i++) {
                coverage[i]++;
            }
        }

        for (int i = 0; i < n; i++) {
            if (coverage[i] < nums[i]) return false;
        }
        return true;
    }
}

class Solution {
    public boolean isZeroArray(int[] nums, int[][] queries) {
        int n = nums.length;
        int[] diff = new int[n + 1];

        for (int[] q : queries) {
            diff[q[0]]++;
            diff[q[1] + 1]--;
        }

        int coverage = 0;
        for (int i = 0; i < n; i++) {
            coverage += diff[i];
            if (coverage < nums[i]) return false;
        }
        return true;
    }
}

class Solution {
    public int minZeroArray(int[] nums, int[][] queries) {
        int n = nums.length;
        for (int k = 0; k <= queries.length; k++) {
            int[] diff = new int[n + 1];
            for (int q = 0; q < k; q++) {
                int l = queries[q][0], r = queries[q][1], val = queries[q][2];
                diff[l] += val;
                diff[r + 1] -= val;
            }
            int coverage = 0;
            boolean ok = true;
            for (int i = 0; i < n; i++) {
                coverage += diff[i];
                if (coverage < nums[i]) { ok = false; break; }
            }
            if (ok) return k;
        }
        return -1;
    }
}

class Solution {
    private boolean feasible(int[] nums, int[][] queries, int k) {
        int n = nums.length;
        int[] diff = new int[n + 1];
        for (int q = 0; q < k; q++) {
            int l = queries[q][0], r = queries[q][1], val = queries[q][2];
            diff[l] += val;
            diff[r + 1] -= val;
        }
        int coverage = 0;
        for (int i = 0; i < n; i++) {
            coverage += diff[i];
            if (coverage < nums[i]) return false;
        }
        return true;
    }

    public int minZeroArray(int[] nums, int[][] queries) {
        if (feasible(nums, queries, 0)) return 0;

        int left = 1, right = queries.length;
        int answer = -1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (feasible(nums, queries, mid)) {
                answer = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        return answer;
    }
}

